INSERT INTO documentation_faq (screen_tag, question, answer, sort_order) VALUES
  ('S-1', 'What is the primary purpose of the dashboard screen?', 'This screen allows a user to view and manage their dashboard data efficiently within the platform.', 0),
  ('S-1', 'How do I search or filter records on this screen?', 'You can use the search bar at the top or the filter dropdowns to narrow down the dashboard list.', 1),
  ('S-1', 'Can I export the data shown here?', 'Yes, if export is supported for dashboard, an "Export CSV" button will be available at the top right of the table.', 2),
  ('S-1', 'What happens if I encounter an error on the dashboard page?', 'Please refresh the page. If the issue persists, contact the system administrator and mention screen ID S-1.', 3),
  ('S-1', 'Is the data on this screen real-time?', 'Yes, the dashboard data is fetched directly from the database and reflects the most recent updates.', 4),
  ('S-1', 'How do I update an entry here?', 'Click on the ''Edit'' icon next to the specific dashboard record to modify its details.', 5),
  ('S-1', 'Are deleted dashboard permanently removed?', 'Usually, deletions are permanent unless an archive feature is explicitly stated for dashboard.', 6),
  ('S-1', 'Why can''t I see certain dashboard?', 'Your access is scoped to your role (user). You will only see dashboard assigned to your specific tenant or profile.', 7),
  ('S-1', 'Is this screen mobile-friendly?', 'Yes, the dashboard layout is responsive and will adapt to smaller screens like smartphones or tablets.', 8),
  ('S-1', 'How do I navigate back to the main dashboard from here?', 'You can click the "Home" icon in the sidebar or use the breadcrumb navigation at the top of the dashboard page.', 9),
